local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst          self.saveData = {}          self.bufferData = {} end) function myComponent:OnSave()     local tmp = {}     tmp.saveData = self.saveData or {}     return tmp end function myComponent:OnLoad(data)     if data ~= nil and self.inst then         self.saveData = data.saveData or {}     end end function myComponent:inSaveData(name)     if not TD.isStr(name) then         return false     end     local saveData = TD.default(self, "saveData")     return saveData[name] ~= nil end function myComponent:value(name, num, persistence, notSyn)     local saveData = TD.default(self, "saveData")     local bufferData = TD.default(self, "bufferData")     if TD.ds() then         local tmp_value = nil         if num ~= nil then             if persistence then                 saveData[name] = num             else                 bufferData[name] = num             end             if not notSyn then                 TD.exeServer(TD.holder("%s_flush_server"), {})             end             tmp_value = num         else             if persistence then                 tmp_value = saveData[name] or bufferData[name]             else                 tmp_value = bufferData[name] or saveData[name]             end         end         return tmp_value     end     if not TD.isStr(name) then         return nil     end     if bufferData[name] ~= nil then         if num ~= nil and bufferData[name] ~= num then             bufferData[name] = num             if not notSyn then                 self:synBufferData(name)             end         end         return bufferData[name]     elseif saveData[name] ~= nil then         if num ~= nil and saveData[name] ~= num then             saveData[name] = num             if not notSyn then                 self:synSaveData(name)             end         end         return saveData[name]     else         if persistence then             if num ~= nil and saveData[name] ~= num then                 saveData[name] = num                 if not notSyn then                     self:synSaveData(name)                 end                 return saveData[name]             end             return saveData[name]         else             if num ~= nil and bufferData[name] ~= num then                 bufferData[name] = num                 if not notSyn then                     self:synBufferData(name)                 end                 return bufferData[name]             end             return bufferData[name]         end     end end function myComponent:changeTab(name, changeFn, notSyn)     local elem = self:get(name)          if not TD.isTab(elem) then         self:value(name, {}, nil, true)         elem = self:get(name)     end     if TD.isTab(elem) and TD.isFn(changeFn) then         changeFn(elem)         if TD.ds() then             TD.exeServer(TD.holder("%s_flush_server"), {})         else             if not notSyn then                 if self:inSaveData(name) then                     self:synSaveData(name)                 else                     self:synBufferData(name)                 end             end         end     end     return elem end function myComponent:init(name, num, persistence, notSyn)     if self:get(name) == nil and num ~= nil then         self:value(name, num, persistence, notSyn)     end end function myComponent:get(name)     return self:value(name) end function myComponent:synBufferData(name)     if TD.server() then         TD.mgn(self.inst, function(comp)             local param = {}             param.key = name             param.data = self:get(name)             param.inst = self.inst             if TD.isTab(param.data) then                 param.data = table.td1madao_clone(param.data)             end             TD.exeServer(TD.holder("%s_flush_server"), param)             comp:server_send(TD.holder("%s_synBufferData"), param)         end)     else         local param = {}         param.key = name         param.data = TD.default(self, "bufferData")[name]         if TD.isTab(param.data) then             param.data = table.td1madao_clone(param.data)         end         TD.exeClient(TD.holder("%s_flush_client"), param)         TD.serverCall(TD.holder("%s_synBufferData"), param)     end end function myComponent:synSaveData(name)     if TD.server() then         TD.mgn(self.inst, function(comp)             local param = {}             param.key = name             param.data = self:get(name)             param.inst = self.inst             if TD.isTab(param.data) then                 param.data = table.td1madao_clone(param.data)             end             TD.exeServer(TD.holder("%s_flush_server"), param)             comp:server_send(TD.holder("%s_synSaveData"), param)         end)     else         local param = {}         param.key = name         param.data = self:get(name)         if TD.isTab(param.data) then             param.data = table.td1madao_clone(param.data)         end         TD.exeClient(TD.holder("%s_flush_client"), param)         TD.serverCall(TD.holder("%s_synSaveData"), param)     end end return myComponent 